const e = $input.first().json;
const execId = e.execution?.id || 'unknown';
const execUrl = e.execution?.url || `https://jerry-hsieh.app.n8n.cloud/execution/${execId}`;
const wfName = e.workflow?.name || 'Supervisor Daily Report';
const nodeName = e.execution?.lastNodeExecuted || e.execution?.error?.node?.name || '未知節點';
const errMsg = e.execution?.error?.message || '未知錯誤';

const msg = [
  '⚠️ 監工日誌系統發生錯誤',
  '',
  `🔴 工作流程：${wfName}`,
  `❌ 失敗節點：${nodeName}`,
  `📋 錯誤訊息：${errMsg.substring(0, 100)}`,
  '',
  '🔁 點擊重試：',
  execUrl
].join('\n');

const flex = {
  to: 'Ubf65144da2093a2cb9e01528d773413f',
  messages: [{
    type: 'flex',
    altText: '⚠️ 監工日誌系統發生錯誤',
    contents: {
      type: 'bubble',
      header: {
        type: 'box',
        layout: 'vertical',
        contents: [{
          type: 'text',
          text: '⚠️ 系統錯誤通知',
          weight: 'bold',
          size: 'lg',
          color: '#ffffff'
        }],
        backgroundColor: '#d9534f'
      },
      body: {
        type: 'box',
        layout: 'vertical',
        spacing: 'sm',
        contents: [
          { type: 'text', text: `工作流程：${wfName}`, wrap: true, size: 'sm' },
          { type: 'text', text: `失敗節點：${nodeName}`, wrap: true, size: 'sm', color: '#d9534f' },
          { type: 'text', text: `錯誤：${errMsg.substring(0, 120)}`, wrap: true, size: 'xs', color: '#666666' }
        ]
      },
      footer: {
        type: 'box',
        layout: 'vertical',
        contents: [{
          type: 'button',
          style: 'primary',
          color: '#1e90ff',
          action: {
            type: 'uri',
            label: '前往 n8n 重試',
            uri: execUrl
          }
        }]
      }
    }
  }]
};

return [{ json: { payload: JSON.stringify(flex) } }];
